            after = cheb(nx, ny, tx, ty)
            # Advantage vs opponent for that target after move
            opd_after = cheb(ox, oy, tx, ty)
            # If after <= opponent distance, we are more likely to secure; otherwise less.
            val = (before - after) * 50 + (opd_after - after) * 20 - after
            # Mild preference to avoid stepping adjacent to obstacles (deterministic and cheap)
            adj_obs = 0
