            before = cheb(sx, sy, tx, ty)
            after = cheb(nx, ny, tx, ty)
            val = (before - after) * 50 - after

        if val > best_val:
            best_val = val
            best_move = (dx, dy)

    return [best_move[0], best_move[1]]

